#include <iostream>
#include <boost/asio.hpp>
#include <boost/thread.hpp>

using boost::asio::ip::tcp;

class TCPServer {
public:
    TCPServer(short port): io_service_(), acceptor_(io_service_, tcp::endpoint(tcp::v4(), port)) {}

    void start() {
        boost::thread t(boost::bind(&TCPServer::run, this));
        t.detach();
    }

    void run() {
        while (true) {
            boost::shared_ptr<tcp::socket> socket(new tcp::socket(io_service_));

            acceptor_.async_accept(*socket, boost::bind(&TCPServer::handle_accept, this, socket,
                boost::asio::placeholders::error));

            io_service_.run();
            io_service_.reset();
        }
    }

    void handle_accept(boost::shared_ptr<tcp::socket> socket, const boost::system::error_code& error) {
        if (!error) {
            boost::shared_ptr<std::string> message(new std::string("Hello, world!\n"));
            boost::asio::async_write(*socket, boost::asio::buffer(*message),
                boost::bind(&TCPServer::handle_write, this, socket, message,
                    boost::asio::placeholders::error));
        }
    }

    void handle_write(boost::shared_ptr<tcp::socket> socket, boost::shared_ptr<std::string> message,
                      const boost::system::error_code& error) {
        if (!error) {
            socket->async_receive(boost::asio::buffer(buffer_), boost::bind(&TCPServer::handle_receive, this, socket,
                boost::asio::placeholders::error, boost::asio::placeholders::bytes_transferred));
        }
    }

    void handle_receive(boost::shared_ptr<tcp::socket> socket, const boost::system::error_code& error, std::size_t bytes_transferred) {
        if (!error) {
            std::cout << "Received message: " << std::string(buffer_.data(), bytes_transferred) << std::endl;
            // 处理接收到的消息

            socket->async_receive(boost::asio::buffer(buffer_), boost::bind(&TCPServer::handle_receive, this, socket,
                boost::asio::placeholders::error, boost::asio::placeholders::bytes_transferred));
        }
    }

private:
    boost::asio::io_service io_service_;
    tcp::acceptor acceptor_;
    boost::array<char, 1024> buffer_;
};

int main() {
    TCPServer server(1234);
    server.start();
    while (true) {}
    return 0;
}
```

在该类中，start函数用于启动独立线程，调用run函数。run函数在一个无限循环中，不断监听来自客户端的连接请求，并通过异步操作处理连接和数据。

当有新的连接请求时，run函数创建一个新的tcp::socket对象，通过acceptor_异步接受连接请求，然后在handle_accept回调函数中，向客户端发送一条消息“Hello, world!\n”。

