class TCPMessage {
public:
    TCPMessage() : header_received_(false) {}

    void reset() {
        header_received_ = false;
        buffer_.consume(buffer_.size());
    }

    void receive(tcp::socket& socket, boost::system::error_code& error) {
        if (!header_received_) {
            boost::asio::async_read(socket, buffer_, boost::asio::transfer_exactly(sizeof(uint32_t)),
                boost::bind(&TCPMessage::handle_header_read, this, boost::asio::placeholders::error));
